const updateExpense = `-- name: UpdateExpense :one
UPDATE expenses
SET title = ?1,
    description = ?2,
    amount = ?3,
    date = ?4,
    paid = ?5,
    paid_at = CASE
      WHEN ?5 = 0 THEN NULL
      WHEN ?6 IS NOT NULL THEN NULLIF(?6, '')
      WHEN paid = 0 THEN CURRENT_TIMESTAMP
      ELSE paid_at
    END
WHERE id = ?7 AND group_id = ?8
RETURNING id, group_id, title, description, amount, date, created_at, updated_at, paid, paid_at
`

type UpdateExpenseParams struct {
	Title       string      `json:"title"`
	Description string      `json:"description"`
	Amount      int64       `json:"amount"`
	Date        string      `json:"date"`
	Paid        int64       `json:"paid"`
	PaidAt      interface{} `json:"paid_at"`
	ID          string      `json:"id"`
	GroupID     string      `json:"group_id"`
}

func (q *Queries) UpdateExpense(ctx context.Context, arg UpdateExpenseParams) (Expense, error) {
	row := q.db.QueryRowContext(ctx, updateExpense,
		arg.Title,
		arg.Description,
		arg.Amount,
		arg.Date,
		arg.Paid,
		arg.PaidAt,
		arg.ID,
		arg.GroupID,
	)
	var i Expense
	err := row.Scan(
		&i.ID,
		&i.GroupID,
		&i.Title,
		&i.Description,
		&i.Amount,
		&i.Date,
		&i.CreatedAt,
		&i.UpdatedAt,
		&i.Paid,
		&i.PaidAt,
	)
	return i, err
}
